render(() => {
const [visible, setVisible] = React.useState(true);

const calendarStyles = {
border: '1px solid rgba(233, 233, 235, 1)',
borderRadius: 'var(--calendar-popover-border-radius, var(--border-radius-16))',
boxShadow: `0px 20px 24px rgba(0, 0, 0, 0.08),
0px 12px 16px rgba(0, 0, 0, 0.04),
0px 4px 8px rgba(0, 0, 0, 0.04),
0px 0px 1px rgba(0, 0, 0, 0.04)`,
};

return (
<div style={{ width: 344 }}>
<div style={calendarStyles}>
<CalendarWithSkeleton calendarVisible={visible} />
</div>
<Gap size={24}/>
<Switch
block={true}
checked={!visible}
label='Скелетонизация контента'
onChange={() => setVisible(!visible)}
/>
</div>
);
});
